module edge_detect(
    input clk,
    input rst_n,
    input a,
    output rise,
    output down
);

reg a_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        a_reg <= 1'b0;
    end else begin
        a_reg <= a;
    end
end

assign rise = (a_reg == 1'b0 && a == 1'b1) ? 1'b1 : 1'b0;
assign down = (a_reg == 1'b1 && a == 1'b0) ? 1'b1 : 1'b0;

endmodule
